 1	import * as React from "react";
 2	import { Tooltip } from "@patternfly/react-core";
 3	
 4	const EllipsisToolTip: React.FC<
 5	  React.PropsWithChildren<{ content: React.ReactNode }>
 6	> = ({ content, children }) => {
 7	  const [showTooltip, setShowTooltip] = React.useState(false);
 8	
 9	  const mouseEnterHandler = (e) => {
10	    if (e.target.offsetWidth !== e.target.scrollWidth && !showTooltip) {
11	      setShowTooltip(true);
12	    } else if (e.target.offsetWidth === e.target.scrollWidth && showTooltip) {
13	      setShowTooltip(false);
14	    }
15	  };
16	
17	  return (
18	    <Tooltip content={content} hidden={!showTooltip}>
19	      <div onMouseEnter={mouseEnterHandler}>{children}</div>
20	    </Tooltip>
21	  );
22	};
23	
24	export default EllipsisToolTip;

